import { z } from "zod";

import { bounds, config } from "../config/index.js";
import { nonEmptyString } from "./common.js";
import {
  DepthBandSchema,
  EnemyDefinitionSchema,
  ItemDefinitionSchema,
  NarrationBeatsSchema,
  NpcDefinitionSchema,
  QuestDefinitionSchema,
  TrapDefinitionSchema,
  type DepthBand,
} from "./entities/index.js";
import { PROTOCOL_VERSION } from "./protocol.js";

export const MANIFEST_LAYOUT_FLAVORS = [
  "open",
  "warren",
  "halls",
  "ring",
  "sanctum",
] as const;

export const ManifestLayoutFlavorSchema = z.enum(MANIFEST_LAYOUT_FLAVORS);

export const ManifestRoomCountRangeSchema = z
  .strictObject({
    min: z.number().int().positive(),
    max: z.number().int().positive(),
  })
  .superRefine((range, ctx) => {
    if (range.min > range.max) {
      ctx.addIssue({
        code: "custom",
        path: ["min"],
        message: "roomCountRange.min must be less than or equal to max",
      });
    }
  });

export const ManifestParamsSchema = z.strictObject({
  bandOrSize: DepthBandSchema,
  roomCountRange: ManifestRoomCountRangeSchema,
  flavor: ManifestLayoutFlavorSchema,
  seed: nonEmptyString,
});

export const ManifestPlacementDistanceSchema = z.enum([
  "near_entrance",
  "far_from_entrance",
]);

export const ManifestPlacementHintSchema = z.strictObject({
  roomIndex: z.number().int().nonnegative().nullable(),
  distance: ManifestPlacementDistanceSchema.nullable(),
  spread: z.boolean(),
});

export const ManifestRosterEntrySchema = EnemyDefinitionSchema.extend({
  placementHint: ManifestPlacementHintSchema.nullable(),
});

export const ManifestItemEntrySchema = ItemDefinitionSchema.extend({
  placementHint: ManifestPlacementHintSchema.nullable(),
});

export const ManifestTrapEntrySchema = TrapDefinitionSchema.extend({
  placementHint: ManifestPlacementHintSchema.nullable(),
});

export const ManifestNpcEntrySchema = NpcDefinitionSchema.extend({
  placementHint: ManifestPlacementHintSchema.nullable(),
});

export const ManifestOriginTagsSummarySchema = z.strictObject({
  made: z.number().int().nonnegative(),
  old_stock: z.number().int().nonnegative(),
  kept: z.number().int().nonnegative(),
});

export const ManifestMetadataSchema = z.strictObject({
  originTags: ManifestOriginTagsSummarySchema,
  callbacks: z.array(nonEmptyString),
  signature: z.boolean(),
});

export const FloorManifestSchema = z
  .strictObject({
    protocolVersion: z.literal(PROTOCOL_VERSION),
    depth: z.number().int().min(1).max(config.runStructure.depthFloors),
    band: DepthBandSchema,
    params: ManifestParamsSchema,
    roster: z.array(ManifestRosterEntrySchema),
    items: z
      .array(ManifestItemEntrySchema)
      .min(config.itemsEconomy.itemsPerFloor.min)
      .max(config.itemsEconomy.itemsPerFloor.max),
    traps: z
      .array(ManifestTrapEntrySchema)
      .min(bounds.trapsNpcsQuests.traps.perFloor.min)
      .max(bounds.trapsNpcsQuests.traps.perFloor.max),
    npcs: z
      .array(ManifestNpcEntrySchema)
      .min(bounds.trapsNpcsQuests.npcs.perFloor.min)
      .max(bounds.trapsNpcsQuests.npcs.perFloor.max),
    quest: QuestDefinitionSchema.nullable(),
    narration: NarrationBeatsSchema,
    metadata: ManifestMetadataSchema,
  })
  .superRefine((manifest, ctx) => {
    enforceBandConsistency(manifest, ctx);
  });

export type ManifestLayoutFlavor = z.infer<typeof ManifestLayoutFlavorSchema>;
export type ManifestRoomCountRange = z.infer<
  typeof ManifestRoomCountRangeSchema
>;
export type ManifestPlacementDistance = z.infer<
  typeof ManifestPlacementDistanceSchema
>;
export type ManifestPlacementHint = z.infer<typeof ManifestPlacementHintSchema>;
export type ManifestRosterEntry = z.infer<typeof ManifestRosterEntrySchema>;
export type ManifestItemEntry = z.infer<typeof ManifestItemEntrySchema>;
export type ManifestTrapEntry = z.infer<typeof ManifestTrapEntrySchema>;
export type ManifestNpcEntry = z.infer<typeof ManifestNpcEntrySchema>;
export type FloorManifest = z.infer<typeof FloorManifestSchema>;

export type ManifestParseError = {
  readonly path: string;
  readonly message: string;
};

export type ParseManifestResult =
  | { readonly ok: true; readonly manifest: FloorManifest }
  | { readonly ok: false; readonly errors: readonly ManifestParseError[] };

export const parseManifest = (raw: string): ParseManifestResult => {
  const extracted = extractFirstJsonObject(raw);
  if (!extracted.ok) {
    return {
      ok: false,
      errors: [{ path: "$", message: extracted.message }],
    };
  }

  let parsed: unknown;
  try {
    parsed = JSON.parse(extracted.json);
  } catch (error) {
    return {
      ok: false,
      errors: [
        {
          path: "$",
          message:
            error instanceof Error
              ? `invalid JSON: ${error.message}`
              : "invalid JSON",
        },
      ],
    };
  }

  const result = FloorManifestSchema.safeParse(parsed);
  if (!result.success) {
    return {
      ok: false,
      errors: result.error.issues.map((issue) => ({
        path: formatIssuePath(issue.path),
        message: issue.message,
      })),
    };
  }

  return { ok: true, manifest: result.data };
};

const enforceBandConsistency = (
  manifest: {
    readonly depth: number;
    readonly band: DepthBand;
    readonly params: {
      readonly bandOrSize: DepthBand;
      readonly roomCountRange: ManifestRoomCountRange;
      readonly flavor: ManifestLayoutFlavor;
    };
    readonly metadata: { readonly signature: boolean };
  },
  ctx: z.RefinementCtx,
): void => {
  const depthBand = config.runStructure.depthBands[manifest.band];
  if (
    manifest.depth < depthBand.minFloor ||
    manifest.depth > depthBand.maxFloor
  ) {
    ctx.addIssue({
      code: "custom",
      path: ["depth"],
      message: `depth must be within the ${manifest.band} band (${depthBand.minFloor}-${depthBand.maxFloor})`,
    });
  }

  if (manifest.params.bandOrSize !== manifest.band) {
    ctx.addIssue({
      code: "custom",
      path: ["params", "bandOrSize"],
      message: "params.bandOrSize must match band",
    });
  }

  const geometry = config.runStructure.floorGeometry[manifest.band];
  if (manifest.params.roomCountRange.min < geometry.rooms.min) {
    ctx.addIssue({
      code: "custom",
      path: ["params", "roomCountRange", "min"],
      message: `roomCountRange.min must be at least ${geometry.rooms.min} for ${manifest.band}`,
    });
  }

  if (manifest.params.roomCountRange.max > geometry.rooms.max) {
    ctx.addIssue({
      code: "custom",
      path: ["params", "roomCountRange", "max"],
      message: `roomCountRange.max must be at most ${geometry.rooms.max} for ${manifest.band}`,
    });
  }

  if (
    !(geometry.layoutFlavors as readonly string[]).includes(
      manifest.params.flavor,
    )
  ) {
    ctx.addIssue({
      code: "custom",
      path: ["params", "flavor"],
      message: `flavor must be allowed for ${manifest.band}`,
    });
  }

  if (
    manifest.metadata.signature &&
    manifest.band !== bounds.directorManifest.signatureMomentBand
  ) {
    ctx.addIssue({
      code: "custom",
      path: ["metadata", "signature"],
      message: `signature floors must be in the ${bounds.directorManifest.signatureMomentBand} band`,
    });
  }
};

const extractFirstJsonObject = (
  raw: string,
):
  | { readonly ok: true; readonly json: string }
  | { readonly ok: false; readonly message: string } => {
  const text = stripMarkdownFence(raw);
  const start = text.indexOf("{");

import { z } from "zod";

import { config } from "../../config/index.js";
import { nonEmptyString } from "../common.js";
import { NarrationLineSchema } from "./common.js";

export const ObservationBeatSchema = z.strictObject({
  id: nonEmptyString,
  triggerTag: nonEmptyString,
  text: NarrationLineSchema,
});

// Provider-facing: structural and text caps come from the config bounds.
export const NarrationBeatsSchema = z.strictObject({
  floorIntro: NarrationLineSchema,
  observations: z
    .array(ObservationBeatSchema)
    .max(config.directorManifest.narrationBeats.triggeredObservationLinesMax),
});

export type NarrationBeats = z.infer<typeof NarrationBeatsSchema>;

import type { GameConfig } from "../../config/index.js";
import type {
  DepthBand,
  EnemyDefinition,
  ItemDefinition,
  NpcDefinition,
  QuestDefinition,
  TrapDefinition,
} from "../../schemas/entities/index.js";
import type {
  ENGINE_VERSION,
  PROTOCOL_VERSION,
} from "../../schemas/protocol.js";
import type { StatusApplication } from "../../schemas/vocab/index.js";

export type SerializablePrimitive = string | number | boolean | null;

export type SerializableValue =
  | SerializablePrimitive
  | readonly SerializableValue[]
  | { readonly [key: string]: SerializableValue };

export type SerializableRecord = {
  readonly [key: string]: SerializableValue;
};

export const ACTIVE_TERMINAL_STATUS = "ACTIVE" as const;

export type ConfiguredTerminalStatus =
  GameConfig["runStructure"]["terminalStates"][keyof GameConfig["runStructure"]["terminalStates"]];

export type TerminalStatus =
  | typeof ACTIVE_TERMINAL_STATUS
  | ConfiguredTerminalStatus;

export interface VersionStamp {
  readonly protocolVersion: typeof PROTOCOL_VERSION;
  readonly engineVersion: typeof ENGINE_VERSION;
}

export interface RunMeta {
  readonly runId: string;
  readonly seed: string;
  readonly depth: number;
  readonly band: DepthBand;
  readonly turn: number;
  readonly terminalStatus: TerminalStatus;
  readonly itemKnowledge: ItemKnowledgeState;
}

export interface ItemKnowledgeState {
  readonly identifiedDefinitionIds: readonly string[];
  readonly bonusRevealedItemInstanceIds: readonly string[];
  readonly chargesByItemInstanceId: {
    readonly [itemInstanceId: string]: number;
  };
}

export interface Position {
  readonly x: number;
  readonly y: number;
}

export interface FloorGeometrySlot {
  readonly refId: string;
  /*
   * PHASE-07A contract: the map module owns this payload's concrete shape.
   * PHASE-06 only requires a stable, serializable geometry reference by id.
   */
  readonly opaque: SerializableRecord | null;
}

export interface FloorState {
  readonly floorId: string;
  readonly depth: number;
  readonly band: DepthBand;
  readonly geometry: FloorGeometrySlot;
}

export interface PlayerItemStack {
  readonly itemInstanceId: string;
  readonly definition: ItemDefinition;
  readonly quantity: number;
  readonly identified: boolean;
}

export type InventorySlot = PlayerItemStack | null;

export interface EquipmentState {
  readonly weapon: PlayerItemStack | null;
  readonly armor: PlayerItemStack | null;
  readonly charms: readonly (PlayerItemStack | null)[];
}

export interface PlayerState {
  readonly hp: {
    readonly current: number;
    readonly max: number;
  };
  readonly level: number;
  readonly xp: number;
  readonly fullness: {
    readonly current: number;
    readonly max: number;
  };
  readonly position: Position;
  readonly inventory: readonly InventorySlot[];
  readonly equipment: EquipmentState;
  readonly statuses: readonly StatusApplication[];
}

export type EntityKind = "enemy" | "npc" | "item" | "trap";

export type EntityIdCounters = {
  readonly [Kind in EntityKind]: number;
};

export type EntityId = `${EntityKind}#${number}`;

export interface EntityRuntimeFields {
  readonly id: EntityId;
  readonly position: Position;
  readonly currentHP: number | null;
  readonly statuses: readonly StatusApplication[];
  readonly behaviorRuntime: SerializableRecord;
}

export interface EnemyEntityInstance extends EntityRuntimeFields {
  readonly kind: "enemy";
  readonly definition: EnemyDefinition;
  readonly currentHP: number;
}

export interface NpcEntityInstance extends EntityRuntimeFields {
  readonly kind: "npc";
  readonly definition: NpcDefinition;
  readonly dialogueRuntime: SerializableRecord;
}

export interface GroundItemEntityInstance extends EntityRuntimeFields {
  readonly kind: "item";
  readonly definition: ItemDefinition;
  readonly currentHP: null;
  readonly quantity: number;
  readonly identified: boolean;
}

export interface TrapEntityInstance extends EntityRuntimeFields {
  readonly kind: "trap";
  readonly definition: TrapDefinition;
  readonly currentHP: null;
  readonly armed: boolean;
}

export type EntityInstance =
  | EnemyEntityInstance
  | NpcEntityInstance
  | GroundItemEntityInstance
  | TrapEntityInstance;

export type EntityMap = {
  readonly [id: string]: EntityInstance;
};

export type QuestRuntimeStatus = "available" | "active" | "completed" | "failed";

export interface QuestRuntime {
  readonly definition: QuestDefinition;
  readonly status: QuestRuntimeStatus;
  readonly progress: SerializableRecord;
}

export interface QuestState {
  readonly quests: {
    readonly [id: string]: QuestRuntime;
  };
  readonly activeQuestIds: readonly string[];
  readonly completedQuestIds: readonly string[];
  readonly failedQuestIds: readonly string[];
}

/*
 * Log extension pattern:
 * later engine systems add event types by declaration-merging this interface.
 * The runtime serializer validates the event envelope and serializable data.
 */
export interface EngineLogEventDataByType {
  readonly state_created: {
    readonly runId: string;
    readonly seed: string;
    readonly depth: number;
    readonly band: DepthBand;
  };
  readonly state_serialized: {
    readonly format: "stable-json";
  };
  readonly state_deserialized: {
    readonly format: "stable-json";
  };
}

export type EngineLogEventType = Extract<
  keyof EngineLogEventDataByType,
  string
>;

export type EngineLogEvent = {
  readonly [Type in EngineLogEventType]: {
    readonly turn: number;
    readonly type: Type;
    readonly data: EngineLogEventDataByType[Type];
  };
}[EngineLogEventType];

export interface RngStreamCursor {
  readonly streamId: string;
  readonly seed: string;
  readonly parentStreamId: string | null;
  readonly draws: number;
}

export interface RngState {
  readonly rootSeed: string;
  readonly streams: {
    readonly [streamId: string]: RngStreamCursor;
  };
}

export interface IdState {
  readonly entityCounters: EntityIdCounters;
}

export interface GameState {
  readonly version: VersionStamp;
  readonly run: RunMeta;
  readonly floor: FloorState;
  readonly player: PlayerState;
  readonly entities: EntityMap;
  readonly quests: QuestState;
  readonly log: readonly EngineLogEvent[];
  readonly rng: RngState;
  readonly ids: IdState;
}

import type {
  EngineLogEvent,
  EngineLogEventType,
  Position,
} from "../state/index.js";

export const formatLogEvent = (event: EngineLogEvent): string => {
  const { type, data, turn } = event;

  switch (type) {
    case "state_created":
      return `t${turn} run ${data.runId} started (seed ${data.seed}, d${data.depth} ${data.band})`;
    case "state_serialized":
      return `t${turn} state serialized (${data.format})`;
    case "state_deserialized":
      return `t${turn} state deserialized (${data.format})`;
    case "run_action_resolved":
      return `t${turn} ${data.actionKind} resolved`;
    case "run_action_illegal":
      return `t${turn} cannot ${data.actionKind}: ${data.reason}`;
    case "run_floor_entered":
      return `t${turn} entered d${data.depth} ${data.band} (${data.rosterCost}/${data.spawnBudget})`;
    case "run_placement_deviation":
      return `t${turn} placement adjusted ${data.requestId}: ${data.reasons.join(", ")}`;
    case "run_boredom":
      return `t${turn} boredom wave ${data.wave} on d${data.depth}: ${formatBoredomReason(data.reason)}`;
    case "run_reinforcement_spawned":
      return `t${turn} reinforcement ${data.definitionId} at ${formatPos(data.position)} (${data.budgetRemaining} budget left)`;
    case "hoard_taken":
      return `t${turn} claimed ${data.name} at ${formatPos(data.position)}`;
    case "moved":
      return `t${turn} ${data.actorId} moved ${data.direction} ${formatPos(data.from)}->${formatPos(data.to)}`;
    case "bumped_wall":
      return `t${turn} ${data.actorId} bumped ${data.direction}: ${data.reason}`;
    case "door_opened":
      return `t${turn} ${data.actorId} opened door ${formatPos(data.at)} (${data.direction})`;
    case "stepped_stairs":
      return `t${turn} ${data.actorId} stepped on ${data.stairs} ${formatPos(data.at)}`;
    case "attack_intent":
      return `t${turn} ${data.actorId} attacks ${data.targetId} (${data.direction})`;
    case "talk_intent":
      return `t${turn} ${data.actorId} talks to ${data.npcId} (${data.direction})`;
    case "attack_hit":
      return `t${turn} ${data.actorId} hit ${data.defenderId} for ${data.damage} (${data.defenderHpBefore}->${data.defenderHpAfter})`;
    case "attack_missed":
      return `t${turn} ${data.actorId} missed ${data.defenderId ?? "target"} (${data.reason})`;
    case "entity_died":
      return `t${turn} ${data.entityId} (${data.kind}) died at ${formatPos(data.position)} +${data.xpYield}xp`;
    case "xp_gained":
      return `t${turn} ${data.actorId} gained ${data.amount}xp from ${data.sourceEntityId} (total ${data.totalXp})`;
    case "status_applied":
      return `t${turn} ${data.status} applied to ${data.entityId} (${data.duration}t)`;
    case "status_refreshed":
      return `t${turn} ${data.status} refreshed on ${data.entityId} (${data.duration}t)`;
    case "status_expired":
      return `t${turn} ${data.status} expired on ${data.entityId}`;
    case "status_dropped_oldest":
      return `t${turn} ${data.status} dropped from ${data.entityId} (cap)`;
    case "status_tick":
      return `t${turn} ${data.status} tick on ${data.entityId} HP${data.hpDelta >= 0 ? "+" : ""}${data.hpDelta}`;
    case "level_up":
      return `t${turn} ${data.actorId} level ${data.levelBefore}->${data.levelAfter} HP ${data.maxHpBefore}/${data.currentHpBefore}->${data.maxHpAfter}/${data.currentHpAfter}`;
    case "starvation":
      return `t${turn} ${data.actorId} starved HP ${data.hpBefore}->${data.hpAfter} (fullness ${data.fullness})`;
    case "item_picked_up":
      return `t${turn} picked up ${data.definitionId} x${data.quantity}${data.stacked ? " (stacked)" : ""}`;
    case "item_dropped":
      return `t${turn} dropped ${data.definitionId} x${data.quantity} at ${formatPos(data.position)}`;
    case "item_equipped":
      return `t${turn} equipped ${data.definitionId} in ${formatEquipSlot(data.slot)}${data.swappedItemInstanceId === null ? "" : ` (swapped ${data.swappedItemInstanceId})`}`;
    case "item_unequipped":
      return `t${turn} unequipped ${data.definitionId} from ${formatEquipSlot(data.slot)} to slot ${data.inventorySlot}`;
    case "item_curse_announced":
      return `t${turn} curse revealed on ${data.definitionId} in ${formatEquipSlot(data.slot)}`;
    case "effect_executed":
      return `t${turn} effect ${data.verb} ${data.sourceId ?? "-"}->${data.targetId ?? "-"}`;
    case "effect_rejected":
      return `t${turn} effect ${data.verb} rejected (${data.code}): ${data.message}`;
    case "enemy_moved":
      return `t${turn} ${data.actorId} moved ${data.direction} ${formatPos(data.from)}->${formatPos(data.to)}`;
    case "enemy_waited":
      return `t${turn} ${data.actorId} waited`;
    case "enemy_ability_used":
      return `t${turn} ${data.actorId} used ability ${data.abilityIndex} on ${data.targetId ?? "-"} (cd ${data.cooldownTurns})`;
    case "thief_item_stolen":
      return `t${turn} ${data.actorId} stole ${data.definitionId} x${data.quantity}`;
    case "ambusher_revealed":
      return `t${turn} ambusher ${data.actorId} revealed`;
    case "mimic_revealed":
      return `t${turn} mimic ${data.actorId} revealed`;
    case "pack_hunter_engaged":
      return `t${turn} pack hunter ${data.actorId} engaged (${data.allyIds.length}/${data.threshold})`;
    case "item_triggered":
      return `t${turn} item ${data.definitionId} triggered (${data.trigger})${data.whiffed ? " whiff" : ""}`;
    case "item_identified":
      return `t${turn} identified ${data.definitionId} (${data.category})`;
    case "item_consumed":
      return `t${turn} consumed ${data.definitionId} x${data.quantityBefore}->${data.quantityAfter}`;
    case "item_charge_used":
      return `t${turn} used charge on ${data.definitionId} (${data.chargesBefore}->${data.chargesAfter})`;
    case "item_depleted":
      return `t${turn} depleted ${data.definitionId}`;
    case "item_proc_checked":
      return `t${turn} proc ${data.trigger} on ${data.definitionId} ${data.chancePercent}% -> ${data.triggered ? "yes" : "no"}`;
    case "item_proc_triggered":
      return `t${turn} proc ${data.trigger} fired on ${data.definitionId}`;
    case "trap_step_triggered":
      return `t${turn} trap ${data.definitionId} triggered by ${data.actorId}`;
    case "dialogue_opened":
      return `t${turn} dialogue with ${data.npcId} at ${data.nodeId}`;
    case "dialogue_choice_selected":
      return `t${turn} ${data.npcId} choice ${data.choiceId} at ${data.nodeId}`;
    case "dialogue_ended":
      return `t${turn} dialogue ended with ${data.npcId}`;
    case "dialogue_flag_set":
      return `t${turn} ${data.npcId} flag ${data.flag}`;
    case "barter_opened":
      return `t${turn} barter opened with ${data.npcId}`;
    case "quest_offer_hook":
      return `t${turn} quest hook ${data.questHookId} from ${data.npcId}`;
    case "quest_offered":
      return `t${turn} quest offered ${data.questId} from ${data.npcId}`;
    case "quest_accepted":
      return `t${turn} accepted quest ${data.questId}`;
    case "quest_refused":
      return `t${turn} refused quest ${data.questId}`;
    case "quest_completed":
      return `t${turn} completed quest ${data.questId}${data.rewardCoin === null ? "" : ` (+${data.rewardCoin} coin)`}`;
    case "quest_failed":
      return `t${turn} quest ${data.questId} failed: ${data.reason}`;
    case "quest_reward_paid":
      return `t${turn} quest reward ${data.questId} +${data.coin} coin${data.itemDefinitionIds.length === 0 ? "" : ` items:${data.itemDefinitionIds.join(",")}`}`;
    case "quest_escort_moved":
      return "";
    case "quest_item_delivered":
      return `t${turn} delivered ${data.itemDefinitionId} for ${data.questId}`;
    case "barter_buy":
      return `t${turn} bought ${data.definitionId} for ${data.price} from ${data.npcId}`;
    case "barter_sell":
      return `t${turn} sold ${data.definitionId} for ${data.price} to ${data.npcId}`;
    case "action_illegal":
      return `t${turn} illegal ${data.actionKind}: ${data.reason}`;
    case "action_resolved":
      return `t${turn} resolved ${data.actionKind}`;
    case "actor_turn":
      return `t${turn} actor turn ${data.actorId}`;
    case "tick_hook":
      return `t${turn} tick ${data.hook}`;
    case "terminal_state":
      return `t${turn} ${data.status}: ${data.reason}`;
    case "resolver_probe":
      return `t${turn} resolver probe ${data.actionKind}: ${data.label}`;
    case "tick_registry_probe":
      return `t${turn} tick registry probe ${data.hook}: ${data.label}`;
    default:
      return assertNever(event);
  }
};

const formatPos = (position: Position): string =>
  `(${position.x},${position.y})`;

const formatEquipSlot = (
  slot:
    | { readonly kind: "weapon" }
    | { readonly kind: "armor" }
    | { readonly kind: "charm"; readonly index: number },
): string =>
  slot.kind === "charm" ? `charm[${slot.index}]` : slot.kind;

const formatBoredomReason = (
  reason: "reinforcement_spawned" | "budget_exhausted" | "no_legal_cell",
): string => {
  switch (reason) {
    case "reinforcement_spawned":
      return "reinforcements arrive";
    case "budget_exhausted":
      return "no budget remains";
    case "no_legal_cell":
      return "no room to enter";
  }
};

const assertNever = (value: never): never => {
  throw new Error(`unhandled log event: ${JSON.stringify(value)}`);
};

