  "state_created",
  "state_serialized",
  "state_deserialized",
  "run_action_resolved",
  "run_action_illegal",
  "run_floor_entered",
  "run_placement_deviation",
  "run_boredom",
  "run_reinforcement_spawned",
  "hoard_taken",
  "moved",
  "bumped_wall",
  "door_opened",
  "stepped_stairs",
  "attack_intent",
  "talk_intent",
  "attack_hit",
  "attack_missed",
  "entity_died",
  "xp_gained",
  "status_applied",
