import {
  bounds,
  config as defaultConfig,
  type GameConfig,
} from "../../config/index.js";
import {
  ENGINE_VERSION,
  PROTOCOL_VERSION,
} from "../../schemas/protocol.js";
import type { DepthBand } from "../../schemas/entities/index.js";
import { createClock } from "../clock/index.js";
import {
  ACTIVE_TERMINAL_STATUS,
  type EntityId,
  type EntityIdCounters,
  type EntityKind,
  type GameState,
  type Position,
} from "./types.js";

export const ROOT_RNG_STREAM_ID = "root" as const;

export const createInitialEntityCounters = (): EntityIdCounters => ({
  enemy: 0,
  npc: 0,
  item: 0,
  trap: 0,
});

export interface EntityIdAllocation {
  readonly id: EntityId;
  readonly entityCounters: EntityIdCounters;
}

export const allocateEntityId = (
  counters: EntityIdCounters,
  kind: EntityKind,
): EntityIdAllocation => {
  const next = counters[kind] + 1;

  return {
    id: `${kind}#${next}` as EntityId,
    entityCounters: {
      ...counters,
      [kind]: next,
    },
  };
};

export const depthBandForDepth = (
  depth: number,
  gameConfig: GameConfig = defaultConfig,
): DepthBand => {
  if (!Number.isSafeInteger(depth)) {
    throw new RangeError("depth must be a safe integer");
  }

  for (const [band, range] of depthBandEntries(gameConfig)) {
    if (depth >= range.minFloor && depth <= range.maxFloor) {
      return band;
    }
  }

  throw new RangeError(`depth ${depth} is outside configured depth bands`);
};

export const createInitialState = (
  seed: string,
  gameConfig: GameConfig = defaultConfig,
): GameState => {
  const turn = createClock().now();
  const depth = initialDepth(gameConfig);
  const band = depthBandForDepth(depth, gameConfig);
  const runId = runIdForSeed(seed);
  const startPosition = unplacedPosition();
  const playerHp = gameConfig.playerCharacter.stats.hp.start;
  const playerFullness = gameConfig.playerCharacter.stats.fullness.start;

  return {
    version: {
      protocolVersion: PROTOCOL_VERSION,
      engineVersion: ENGINE_VERSION,
    },
    run: {
      runId,
      seed,
      depth,
      band,
      turn,
      terminalStatus: ACTIVE_TERMINAL_STATUS,
      itemKnowledge: {
        identifiedDefinitionIds: [],
        bonusRevealedItemInstanceIds: [],
        chargesByItemInstanceId: {},
      },
    },
    floor: {
      floorId: `floor#${depth}`,
      depth,
      band,
      geometry: {
        refId: `floor-geometry#${depth}`,
        opaque: null,
      },
    },
    player: {
      hp: {
        current: playerHp,
        max: playerHp,
      },
      level: gameConfig.playerCharacter.stats.level.start,
      xp: 0,
      fullness: {
        current: playerFullness,
        max: bounds.playerCharacter.fullnessCap,
      },
      position: startPosition,
      inventory: Array.from(
        { length: gameConfig.playerCharacter.inventory.slots },
        () => null,
      ),
      equipment: {
        weapon: null,
        armor: null,
        charms: Array.from(
          { length: gameConfig.playerCharacter.equipmentSlots.charms },
          () => null,
        ),
      },
      statuses: [],
    },
    entities: {},
    quests: {
      quests: {},
      activeQuestIds: [],
      completedQuestIds: [],
      failedQuestIds: [],
    },
    log: [
      {
        turn,
        type: "state_created",
        data: {
          runId,
          seed,
          depth,
          band,
        },
      },
    ],
    rng: {
      rootSeed: seed,
      streams: {
        [ROOT_RNG_STREAM_ID]: {
          streamId: ROOT_RNG_STREAM_ID,
          seed,
          parentStreamId: null,
          draws: 0,
        },
      },
    },
    ids: {
      entityCounters: createInitialEntityCounters(),
    },
  };
};

const runIdForSeed = (seed: string): string => `run#${seed}`;

const unplacedPosition = (): Position => ({
  x: 0,
  y: 0,
});

const initialDepth = (gameConfig: GameConfig): number => {
  const entries = depthBandEntries(gameConfig);
  const firstEntry = entries[0];

  if (firstEntry === undefined) {
    throw new RangeError("config must define at least one depth band");
  }

  let depth = firstEntry[1].minFloor;
  for (const [, range] of entries) {
    if (range.minFloor < depth) {
      depth = range.minFloor;
    }
  }

  return depth;
};

const depthBandEntries = (
  gameConfig: GameConfig,
): readonly [
  DepthBand,
  {
    readonly minFloor: number;
    readonly maxFloor: number;
  },
][] =>
  Object.entries(gameConfig.runStructure.depthBands) as readonly [
    DepthBand,
    {
      readonly minFloor: number;
      readonly maxFloor: number;
    },
  ][];

import { z } from "zod";

import { bounds, config } from "../../config/index.js";
import { nonEmptyString } from "../../schemas/common.js";
import {
  DepthBandSchema,
  EnemyDefinitionSchema,
  ItemDefinitionSchema,
  NpcDefinitionSchema,
  QuestDefinitionSchema,
  TrapDefinitionSchema,
} from "../../schemas/entities/index.js";
import {
  ENGINE_VERSION,
  PROTOCOL_VERSION,
} from "../../schemas/protocol.js";
import { StatusApplicationSchema } from "../../schemas/vocab/index.js";
import { depthBandForDepth } from "./init.js";
import {
  ACTIVE_TERMINAL_STATUS,
  type EntityId,
  type EntityInstance,
  type GameState,
  type SerializableRecord,
  type SerializableValue,
} from "./types.js";

const JsonValueSchema: z.ZodType<SerializableValue> = z.lazy(() =>
  z.union([
    z.string(),
    z.number().finite(),
    z.boolean(),
    z.null(),
    z.array(JsonValueSchema),
    z.record(z.string(), JsonValueSchema),
  ]),
);

const SerializableRecordSchema: z.ZodType<SerializableRecord> = z.record(
  z.string(),
  JsonValueSchema,
);

const EntityIdSchema = z
  .string()
  .regex(/^(enemy|npc|item|trap)#[1-9][0-9]*$/) as z.ZodType<EntityId>;

const PositionSchema = z.strictObject({
  x: z.number().int(),
  y: z.number().int(),
});

const TerminalStatusSchema = z.enum([
  ACTIVE_TERMINAL_STATUS,
  config.runStructure.terminalStates.win,
  config.runStructure.terminalStates.loss,
  config.runStructure.terminalStates.abort,
]);

const VersionStampSchema = z.strictObject({
  protocolVersion: z.literal(PROTOCOL_VERSION),
  engineVersion: z.literal(ENGINE_VERSION),
});

const ItemKnowledgeStateSchema = z.strictObject({
  identifiedDefinitionIds: z.array(nonEmptyString),
  bonusRevealedItemInstanceIds: z.array(nonEmptyString),
  chargesByItemInstanceId: z.record(
    nonEmptyString,
    z.number().int().nonnegative(),
  ),
});

const RunMetaSchema = z
  .strictObject({
    runId: nonEmptyString,
    seed: z.string(),
    depth: z.number().int(),
    band: DepthBandSchema,
    turn: z.number().int().nonnegative(),
    terminalStatus: TerminalStatusSchema,
    itemKnowledge: ItemKnowledgeStateSchema,
  })
  .superRefine((run, ctx) => {
    const expectedBand = expectedBandFor(run.depth, ctx, ["band"]);

    if (expectedBand !== null && run.band !== expectedBand) {
      ctx.addIssue({
        code: "custom",
        path: ["band"],
        message: `band must be derived from depth as ${expectedBand}`,
      });
    }
  });

const FloorGeometrySlotSchema = z.strictObject({
  refId: nonEmptyString,
  opaque: SerializableRecordSchema.nullable(),
});

const FloorStateSchema = z
  .strictObject({
    floorId: nonEmptyString,
    depth: z.number().int(),
    band: DepthBandSchema,
    geometry: FloorGeometrySlotSchema,
  })
  .superRefine((floor, ctx) => {
    const expectedBand = expectedBandFor(floor.depth, ctx, ["band"]);

    if (expectedBand !== null && floor.band !== expectedBand) {
      ctx.addIssue({
        code: "custom",
        path: ["band"],
        message: `band must be derived from depth as ${expectedBand}`,
      });
    }
  });

const PlayerItemStackSchema = z.strictObject({
  itemInstanceId: nonEmptyString,
  definition: ItemDefinitionSchema,
  quantity: z
    .number()
    .int()
    .positive()
    .max(config.playerCharacter.inventory.identicalConsumableStackLimit),
  identified: z.boolean(),
});

const PlayerStateSchema = z
  .strictObject({
    hp: z.strictObject({
      current: z.number().int().nonnegative().max(bounds.playerCharacter.hpCap),
      max: z.number().int().positive().max(bounds.playerCharacter.hpCap),
    }),
    level: z
      .number()
      .int()
      .min(config.playerCharacter.stats.level.start)
      .max(bounds.playerCharacter.levelCap),
    xp: z.number().int().nonnegative(),
    fullness: z.strictObject({
      current: z
        .number()
        .int()
        .nonnegative()
        .max(bounds.playerCharacter.overfedFullnessCap),
      max: z
        .number()
        .int()
        .positive()
        .max(bounds.playerCharacter.overfedFullnessCap),
    }),
    position: PositionSchema,
    inventory: z
      .array(PlayerItemStackSchema.nullable())
      .length(config.playerCharacter.inventory.slots),
    equipment: z.strictObject({
      weapon: PlayerItemStackSchema.nullable(),
      armor: PlayerItemStackSchema.nullable(),
      charms: z
        .array(PlayerItemStackSchema.nullable())
        .length(config.playerCharacter.equipmentSlots.charms),
    }),
    statuses: z.array(StatusApplicationSchema),
  })
  .superRefine((player, ctx) => {
    if (player.hp.current > player.hp.max) {
      ctx.addIssue({
        code: "custom",
        path: ["hp", "current"],
        message: "current HP must not exceed max HP",
      });
    }

    if (player.fullness.current > player.fullness.max) {
      ctx.addIssue({
        code: "custom",
        path: ["fullness", "current"],
        message: "current fullness must not exceed max fullness",
      });
    }
  });

const EntityRuntimeFieldsSchema = {
  id: EntityIdSchema,
  position: PositionSchema,
  currentHP: z.number().int().nonnegative().nullable(),
  statuses: z.array(StatusApplicationSchema),
  behaviorRuntime: SerializableRecordSchema,
} as const;

const EnemyEntityInstanceSchema = z.strictObject({
  ...EntityRuntimeFieldsSchema,
  kind: z.literal("enemy"),
  definition: EnemyDefinitionSchema,
  currentHP: z.number().int().nonnegative(),
});

const NpcEntityInstanceSchema = z.strictObject({
  ...EntityRuntimeFieldsSchema,
  kind: z.literal("npc"),
  definition: NpcDefinitionSchema,
  dialogueRuntime: SerializableRecordSchema,
});

const GroundItemEntityInstanceSchema = z.strictObject({
  ...EntityRuntimeFieldsSchema,
  kind: z.literal("item"),
  definition: ItemDefinitionSchema,
  currentHP: z.null(),
  quantity: z
    .number()
    .int()
    .positive()
    .max(config.playerCharacter.inventory.identicalConsumableStackLimit),
  identified: z.boolean(),
