import {
  getFallbackFloor,
  type FallbackContentPack,
} from "../../harness/content-loader.js";
import type {
  EnemyDefinition,
  ItemDefinition,
  NpcDefinition,
  TrapDefinition,
} from "../../schemas/entities/index.js";
